public static int mystery(int n) {
    if (n <= 1)
        return 1;
    else
        return n * mystery(n - 1);
}

public static void recur(String s) {
    if (s.length() == 0) return;
    recur(s.substring(1));
    System.out.print(s.charAt(0));
}

public static void mystery(int n) {
    if (n > 0) {
        mystery(n / 10);
        System.out.print(n % 10);
    }
}

